import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { AdminService } from '../../../services/api';
import { ArrowLeft, Save } from 'lucide-react';
import toast from 'react-hot-toast';

export const AdminSeriesForm = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [formData, setFormData] = useState({
    Title_En: '',
    Artist_ID: '',
    Description: ''
  });

  useEffect(() => {
    if (id) {
      AdminService.getSeriesById(id).then((res: any) => {
        setFormData(res.data);
      }).catch(() => toast.error("Error loading series"));
    }
  }, [id]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    try {
      await AdminService.upsertSeries(formData);
      toast.success(id ? "Series Updated" : "Series Created");
      navigate('/admin/series');
    } catch (err) {
      toast.error("Operation Failed");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto p-8 space-y-10">
      <button onClick={() => navigate(-1)} className="flex items-center gap-2 text-gray-400 font-bold text-[10px] uppercase tracking-widest hover:text-primary transition-colors">
        <ArrowLeft size={14} /> Back
      </button>

      <div className="bg-[#0f0f0f] p-10 rounded-[3rem] border border-white/5 shadow-xl">
        <h2 className="text-3xl font-black italic uppercase mb-8">{id ? 'Edit' : 'New'} <span className="text-primary">Series</span></h2>
        <form onSubmit={handleSubmit} className="space-y-6">
          <div className="space-y-2">
            <label className="text-[10px] font-black uppercase text-gray-500 ml-2">Series Title (English)</label>
            <input value={formData.Title_En} onChange={e => setFormData({...formData, Title_En: e.target.value})} className="w-full bg-white/5 border border-white/10 p-4 rounded-xl outline-none focus:border-primary text-white" required />
          </div>
          <div className="space-y-2">
            <label className="text-[10px] font-black uppercase text-gray-500 ml-2">Artist ID</label>
            <input value={formData.Artist_ID} onChange={e => setFormData({...formData, Artist_ID: e.target.value})} className="w-full bg-white/5 border border-white/10 p-4 rounded-xl outline-none focus:border-primary text-white" required />
          </div>
          <button type="submit" disabled={loading} className="w-full bg-primary text-black font-black uppercase py-4 rounded-xl hover:bg-yellow-500 transition-all flex items-center justify-center gap-2">
            <Save size={18} /> {id ? 'Save Changes' : 'Create Series'}
          </button>
        </form>
      </div>
    </div>
  );
};
